+/**
+ * Tests for animations/motion-variants.ts — Framer Motion config
+ */
+import { describe, it, expect } from "vitest";
+import {
+  TIMING,
+  EASING,
+  transitions,
+  fadeUp,
+  fadeIn,
+  scaleIn,
+  popIn,
+  slideInRight,
+  slideInLeft,
+  blurIn,
+  staggerContainer,
+  staggerFast,
+  staggerNormal,
+  staggerSlow,
+  cardHover,
+  buttonHover,
+  buttonTap,
+  iconHover,
+  fadeOut,
+  scaleOut,
+  slideOutDown,
+  pageFade,
+  pageSlideUp,
+  backdrop,
+  modalContent,
+  bottomSheet,
+  accordionContent,
+  skeletonShimmer,
+  spinner,
+  withDelay,
+  viewport,
+} from "./motion-variants";
+
+describe("motion-variants", () => {
+  describe("TIMING", () => {
+    it("has expected timing values", () => {
+      expect(TIMING.micro).toBe(0.15);
